import React, { useState, useMemo } from "react";
import styles from "./FindJobPage.module.css";
import { MainLayout } from "../../layouts";
import { useLanguage } from "../../translet/LanguageContext";

// Mock interpreter job dataset - easily replaceable with API/database calls
const INTERPRETER_JOBS = [
  {
    id: 1,
    title: "Senior English-Vietnamese Conference Interpreter",
    company: "GlobalSpeak",
    location: "Ho Chi Minh City",
    category: "Conference",
    level: "Senior",
    type: "Full-time",
    salary: "$2,500-3,500",
    tags: ["EN-VI", "Conference", "Business"],
    desc: "Lead simultaneous interpretation for international conferences, business summits, and diplomatic events.",
    // Extended details for popup
    contactEmail: "hr@globalspeak.com",
    contactPhone: "+84 28 3822 1234",
    companyAddress: "123 Nguyen Hue Street, District 1, Ho Chi Minh City",
    requirements: [
      "Bachelor's degree in Linguistics, Translation, or related field",
      "5+ years of conference interpretation experience",
      "Fluent in English and Vietnamese",
      "Experience with simultaneous interpretation equipment",
      "Professional certification preferred"
    ],
    benefits: [
      "Competitive salary with performance bonuses",
      "Health insurance and dental coverage",
      "Professional development opportunities",
      "Flexible working arrangements",
      "Annual conference attendance budget"
    ],
    workingHours: "Monday - Friday, 8:00 AM - 5:00 PM",
    deadline: "2025-10-15"
  },
  {
    id: 2,
    title: "Medical Interpreter (Japanese-Vietnamese)",
    company: "MedLingua",
    location: "Hanoi",
    category: "Medical",
    level: "Mid",
    type: "Contract",
    salary: "$1,800-2,200",
    tags: ["JA-VI", "Medical", "Healthcare"],
    desc: "Provide interpretation services for Japanese patients in Vietnamese hospitals and medical facilities.",
    contactEmail: "careers@medlingua.vn",
    contactPhone: "+84 24 3936 5678",
    companyAddress: "456 Tran Hung Dao Street, Hoan Kiem District, Hanoi",
    requirements: [
      "Medical interpretation certification",
      "3+ years in healthcare interpretation",
      "Native-level Japanese and Vietnamese",
      "Understanding of medical terminology",
      "HIPAA compliance knowledge"
    ],
    benefits: [
      "Contract-based flexible schedule",
      "Medical terminology training provided",
      "Professional liability insurance",
      "Continuing education support"
    ],
    workingHours: "Flexible schedule, on-call basis",
    deadline: "2025-09-30"
  },
  // Add basic extended data for other jobs (shortened for brevity)
  {
    id: 3,
    title: "Legal Court Interpreter",
    company: "JusticeWords",
    location: "Da Nang",
    category: "Legal",
    level: "Senior",
    type: "Part-time",
    salary: "$150-250/day",
    tags: ["EN-VI", "Legal", "Court"],
    desc: "Certified court interpreter for legal proceedings, depositions, and legal consultations.",
    contactEmail: "legal@justicewords.vn",
    contactPhone: "+84 236 3888 999",
    companyAddress: "789 Bach Dang Street, Hai Chau District, Da Nang",
    requirements: ["Legal interpretation certification", "Court experience required"],
    benefits: ["Flexible schedule", "Legal training provided"],
    workingHours: "As needed, court schedule",
    deadline: "2025-10-01"
  },
  {
    id: 3,
    title: "Legal Court Interpreter",
    company: "JusticeWords",
    location: "Da Nang",
    category: "Legal",
    level: "Senior",
    type: "Part-time",
    salary: "$150-250/day",
    tags: ["EN-VI", "Legal", "Court"],
    desc: "Certified court interpreter for legal proceedings, depositions, and legal consultations.",
  },
  {
    id: 4,
    title: "Remote Business Interpreter",
    company: "VirtualLink",
    location: "Remote",
    category: "Business",
    level: "Mid",
    type: "Freelance",
    salary: "$80-120/hour",
    tags: ["EN-VI", "Remote", "Business"],
    desc: "Provide remote interpretation for business meetings, negotiations, and client calls via video platforms.",
  },
  {
    id: 5,
    title: "Tourism & Travel Guide Interpreter",
    company: "VietnamTours",
    location: "Ho Chi Minh City",
    category: "Tourism",
    level: "Junior",
    type: "Seasonal",
    salary: "$1,200-1,800",
    tags: ["EN-VI", "Tourism", "Culture"],
    desc: "Guide international tourists, provide cultural interpretation and assist with travel experiences.",
  },
  {
    id: 6,
    title: "Technical Interpreter - Manufacturing",
    company: "TechTrans",
    location: "Binh Duong",
    category: "Technical",
    level: "Mid",
    type: "Full-time",
    salary: "$2,000-2,800",
    tags: ["EN-VI", "Manufacturing", "Technical"],
    desc: "Support technical training, equipment installation, and manufacturing process documentation.",
  },
  {
    id: 7,
    title: "Educational Campus Interpreter",
    company: "EduBridge International",
    location: "Hanoi",
    category: "Education",
    level: "Junior",
    type: "Part-time",
    salary: "$60-90/hour",
    tags: ["EN-VI", "Education", "Campus"],
    desc: "Assist international students with academic interpretation, orientation, and campus life support.",
  },
  {
    id: 8,
    title: "Chinese-Vietnamese Business Interpreter",
    company: "SinoViet Partners",
    location: "Ho Chi Minh City",
    category: "Business",
    level: "Senior",
    type: "Full-time",
    salary: "$2,800-3,500",
    tags: ["ZH-VI", "Business", "Trade"],
    desc: "Facilitate China-Vietnam business partnerships, trade negotiations, and investment meetings.",
  },
  {
    id: 9,
    title: "Korean Entertainment Interpreter",
    company: "K-Wave Media",
    location: "Ho Chi Minh City",
    category: "Entertainment",
    level: "Mid",
    type: "Contract",
    salary: "$1,500-2,200",
    tags: ["KO-VI", "Entertainment", "Media"],
    desc: "Support Korean entertainment events, celebrity interviews, and cultural exchange programs.",
  },
  {
    id: 10,
    title: "Pharmaceutical Research Interpreter",
    company: "PharmaGlobal",
    location: "Remote",
    category: "Medical",
    level: "Senior",
    type: "Contract",
    salary: "$3,000-4,200",
    tags: ["EN-VI", "Pharmaceutical", "Research"],
    desc: "Specialized interpretation for clinical trials, research meetings, and regulatory compliance discussions.",
  },
];

const unique = (arr) => Array.from(new Set(arr));

export default function FindJobPage() {
  const { t } = useLanguage();
  const [keyword, setKeyword] = useState("");
  const [location, setLocation] = useState("");
  const [category, setCategory] = useState("");
  const [level, setLevel] = useState("");
  const [salaryRange, setSalaryRange] = useState("");
  const [page, setPage] = useState(1);
  const [selectedJob, setSelectedJob] = useState(null);
  const [showJobDetail, setShowJobDetail] = useState(false);
  const pageSize = 9; // 3 x 3 layout

  // Mock user state - replace with actual auth context later
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [hasPaidPlan, setHasPaidPlan] = useState(false);

  const categories = useMemo(
    () => unique(INTERPRETER_JOBS.map((j) => j.category)),
    []
  );
  const locations = useMemo(
    () => unique(INTERPRETER_JOBS.map((j) => j.location)),
    []
  );
  const levels = useMemo(
    () => unique(INTERPRETER_JOBS.map((j) => j.level)),
    []
  );

  // Helper function to extract salary range for filtering
  const getSalaryValue = (salaryStr) => {
    const match = salaryStr.match(/\$(\d+(?:,\d+)*)/);
    return match ? parseInt(match[1].replace(/,/g, '')) : 0;
  };

  // Helper function to handle job application
  const handleApplyJob = (job) => {
    setSelectedJob(job);
    setShowJobDetail(true);
  };

  const closeJobDetail = () => {
    setShowJobDetail(false);
    setSelectedJob(null);
  };

  const filtered = useMemo(() => {
    return INTERPRETER_JOBS.filter((j) => {
      const kw = keyword.trim().toLowerCase();
      if (
        kw &&
        !(
          j.title.toLowerCase().includes(kw) ||
          j.company.toLowerCase().includes(kw) ||
          j.tags.some((tg) => tg.toLowerCase().includes(kw))
        )
      )
        return false;
      if (location && j.location !== location) return false;
      if (category && j.category !== category) return false;
      if (level && j.level !== level) return false;
      
      // Salary range filtering
      if (salaryRange) {
        const jobSalary = getSalaryValue(j.salary);
        switch (salaryRange) {
          case "0-1000":
            if (jobSalary > 1000) return false;
            break;
          case "1000-2000":
            if (jobSalary < 1000 || jobSalary > 2000) return false;
            break;
          case "2000-3000":
            if (jobSalary < 2000 || jobSalary > 3000) return false;
            break;
          case "3000+":
            if (jobSalary < 3000) return false;
            break;
          default:
            break;
        }
      }
      
      return true;
    });
  }, [keyword, location, category, level, salaryRange]);

  const totalPages = Math.ceil(filtered.length / pageSize) || 1;
  const pageSafe = Math.min(page, totalPages);
  const slice = filtered.slice((pageSafe - 1) * pageSize, pageSafe * pageSize);

  function submit(e) {
    e.preventDefault();
    setPage(1);
  }
  function reset() {
    setKeyword("");
    setLocation("");
    setCategory("");
    setLevel("");
    setSalaryRange("");
    setPage(1);
  }

  return (
    <MainLayout>
      <div className={styles.findJobRoot}>
        <div className={styles.container}>
          <header className={styles.header}>
            <h1 className={styles.title}>{t("findJob.title")}</h1>
            <p className={styles.subtitle}>{t("findJob.subtitle")}</p>
            
            {/* Temporary test controls - remove in production */}
            <div style={{display: 'flex', gap: '10px', justifyContent: 'center', marginTop: '16px'}}>
              <button 
                onClick={() => setIsLoggedIn(!isLoggedIn)}
                style={{
                  padding: '8px 16px',
                  borderRadius: '8px',
                  border: '1px solid #ccc',
                  background: isLoggedIn ? '#4ade80' : '#f3f4f6',
                  color: isLoggedIn ? 'white' : 'black',
                  cursor: 'pointer'
                }}
              >
                {isLoggedIn ? 'Logged In' : 'Not Logged In'}
              </button>
              <button 
                onClick={() => setHasPaidPlan(!hasPaidPlan)}
                style={{
                  padding: '8px 16px',
                  borderRadius: '8px',
                  border: '1px solid #ccc',
                  background: hasPaidPlan ? '#3b82f6' : '#f3f4f6',
                  color: hasPaidPlan ? 'white' : 'black',
                  cursor: 'pointer'
                }}
              >
                {hasPaidPlan ? 'Paid Plan' : 'Free Plan'}
              </button>
            </div>
          </header>

          <form className={styles.searchBar} onSubmit={submit}>
            <div className={styles.field}>
              <label>{t("findJob.keywordLabel")}</label>
              <input
                value={keyword}
                onChange={(e) => setKeyword(e.target.value)}
                placeholder={t("findJob.keywordPlaceholder")}
              />
            </div>
            <div className={styles.field}>
              <label>{t("findJob.locationLabel")}</label>
              <select
                value={location}
                onChange={(e) => setLocation(e.target.value)}
              >
                <option value="">{t("findJob.allLocations")}</option>
                {locations.map((l) => (
                  <option key={l} value={l}>
                    {l}
                  </option>
                ))}
              </select>
            </div>
            <div className={styles.field}>
              <label>{t("findJob.specializationLabel")}</label>
              <select
                value={category}
                onChange={(e) => setCategory(e.target.value)}
              >
                <option value="">{t("findJob.allSpecializations")}</option>
                {categories.map((c) => (
                  <option key={c} value={c}>
                    {c}
                  </option>
                ))}
              </select>
            </div>
            <div className={styles.field}>
              <label>{t("findJob.levelLabel")}</label>
              <select
                value={level}
                onChange={(e) => setLevel(e.target.value)}
              >
                <option value="">{t("findJob.allLevels")}</option>
                {levels.map((l) => (
                  <option key={l} value={l}>
                    {l}
                  </option>
                ))}
              </select>
            </div>
            <div className={styles.field}>
              <label>{t("findJob.salaryLabel")}</label>
              <select
                value={salaryRange}
                onChange={(e) => setSalaryRange(e.target.value)}
              >
                <option value="">{t("findJob.allSalaryRanges")}</option>
                <option value="0-1000">{t("findJob.salaryUnder1000")}</option>
                <option value="1000-2000">{t("findJob.salary1000to2000")}</option>
                <option value="2000-3000">{t("findJob.salary2000to3000")}</option>
                <option value="3000+">{t("findJob.salary3000plus")}</option>
              </select>
            </div>
            <div className={styles.actions}>
              <button type="submit" className={styles.searchBtn}>
                {t("findJob.searchBtn")}
              </button>
              <button type="button" onClick={reset} className={styles.resetBtn}>
                {t("findJob.clearBtn")}
              </button>
            </div>
          </form>

          <div className={styles.jobsGrid}>
            {slice.length === 0 && (
              <div className={styles.empty}>{t("findJob.noJobsFound")}</div>
            )}
            {slice.map((job) => (
              <div key={job.id} className={styles.jobCard}>
                <div className={styles.jobTop}>
                  <div className={styles.logo}>{job.company[0]}</div>
                  <div className={styles.jobInfo}>
                    <h3 className={styles.jobTitle}>{job.title}</h3>
                    <p className={styles.company}>{job.company}</p>
                    <div className={styles.meta}>
                      <span>📍 {job.location}</span>
                      <span>🎯 {job.category}</span>
                      <span>💼 {job.type}</span>
                      <span>⭐ {job.level}</span>
                      <span>💰 {job.salary}</span>
                    </div>
                  </div>
                </div>
                <p className={styles.desc}>{job.desc}</p>
                <div className={styles.tags}>
                  {job.tags.map((tg) => (
                    <span key={tg}>{tg}</span>
                  ))}
                </div>
                <div className={styles.cardActions}>
                  <button 
                    className={styles.applyBtn}
                    onClick={() => handleApplyJob(job)}
                  >
                    {t("common.apply")}
                  </button>
                  <button className={styles.saveBtn}>{t("common.save")}</button>
                </div>
              </div>
            ))}
          </div>

          <div className={styles.pagination}>
            {Array.from({ length: totalPages }).map((_, i) => {
              const p = i + 1;
              return (
                <button
                  key={p}
                  onClick={() => setPage(p)}
                  className={`${styles.pageBtn} ${
                    p === pageSafe ? styles.active : ""
                  }`}
                >
                  {p}
                </button>
              );
            })}
          </div>

          {/* Job Detail Modal */}
          {showJobDetail && selectedJob && (
            <div className={styles.modalOverlay} onClick={closeJobDetail}>
              <div className={styles.modalContent} onClick={(e) => e.stopPropagation()}>
                <div className={styles.modalHeader}>
                  <h2 className={styles.modalTitle}>{selectedJob.title}</h2>
                  <button className={styles.closeBtn} onClick={closeJobDetail}>
                    ×
                  </button>
                </div>
                
                <div className={styles.modalBody}>
                  <div className={styles.jobDetailHeader}>
                    <div className={styles.companyInfo}>
                      <div className={styles.modalLogo}>{selectedJob.company[0]}</div>
                      <div>
                        <h3 className={styles.companyName}>{selectedJob.company}</h3>
                        <div className={styles.modalMeta}>
                          <span>📍 {selectedJob.location}</span>
                          <span>🎯 {selectedJob.category}</span>
                          <span>⭐ {selectedJob.level}</span>
                          <span>💰 {selectedJob.salary}</span>
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className={styles.jobDescription}>
                    <h4>📋 Job Description</h4>
                    <p>{selectedJob.desc}</p>
                  </div>

                  {selectedJob.requirements && (
                    <div className={styles.jobSection}>
                      <h4>🎯 Requirements</h4>
                      <ul>
                        {selectedJob.requirements.map((req, index) => (
                          <li key={index}>{req}</li>
                        ))}
                      </ul>
                    </div>
                  )}

                  {selectedJob.benefits && (
                    <div className={styles.jobSection}>
                      <h4>🎁 Benefits & Perks</h4>
                      <ul>
                        {selectedJob.benefits.map((benefit, index) => (
                          <li key={index}>{benefit}</li>
                        ))}
                      </ul>
                    </div>
                  )}

                  <div className={styles.jobDetails}>
                    <div className={styles.detailItem}>
                      <strong>🕒 Working Hours</strong>
                      <span>{selectedJob.workingHours || "Standard business hours"}</span>
                    </div>
                    <div className={styles.detailItem}>
                      <strong>📅 Application Deadline</strong>
                      <span>{selectedJob.deadline || "Not specified"}</span>
                    </div>
                  </div>

                  {/* Contact Information - Blurred for non-logged/non-paid users */}
                  <div className={`${styles.contactSection} ${(!isLoggedIn || !hasPaidPlan) ? styles.blurred : ''}`}>
                    <h4>Contact Information</h4>
                    <div className={styles.contactDetails}>
                      <div className={styles.contactItem}>
                        <strong>📧 Email:</strong>
                        <span>{selectedJob.contactEmail || "Not available"}</span>
                      </div>
                      <div className={styles.contactItem}>
                        <strong>📞 Phone:</strong>
                        <span>{selectedJob.contactPhone || "Not available"}</span>
                      </div>
                      <div className={styles.contactItem}>
                        <strong>📍 Address:</strong>
                        <span>{selectedJob.companyAddress || "Not available"}</span>
                      </div>
                    </div>
                    
                    {(!isLoggedIn || !hasPaidPlan) && (
                      <div className={styles.upgradePrompt}>
                        <div className={styles.promptContent}>
                          <h5>🔒 Unlock Contact Details</h5>
                          <p>
                            {!isLoggedIn 
                              ? "Please log in to view contact information"
                              : "Upgrade to a paid plan to access contact details"
                            }
                          </p>
                          <div className={styles.promptActions}>
                            {!isLoggedIn && (
                              <button className={styles.loginBtn}>Log In</button>
                            )}
                            <button className={styles.upgradeBtn}>Upgrade Plan</button>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>

                  <div className={styles.modalActions}>
                    <button className={styles.applyNowBtn}>Apply Now</button>
                    <button className={styles.saveJobBtn}>Save Job</button>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </MainLayout>
  );
}
